String? // JSON-encoded array of people names\n  canvasId       String?\n\n  @@unique([courseId, canvasId])\n  @@index([courseId])\n  @@index([dueDate])\n  @@index([status])\n}\n\nmodel Note {\n  id          Int              @id @default(autoincrement())\n  user        User             @relation(fields: [userId], references: [id])\n  userId      Int\n  course      UniCourse?       @relation(fields: [courseId], references: [id])\n  courseId    Int?\n  title       String\n  content     String\n  createdAt   DateTime         @default(now())\n  attachments NoteAttachment[]\n\n  @@index([userId])\n  @@index([courseId])\n  @@index([createdAt])\n}\n\nmodel NoteAttachment {\n  id        Int      @id @default(autoincrement())\n  note      Note     @relation(fields: [noteId], references: [id], onDelete: Cascade)\n  noteId    Int\n  name      String\n  url       String\n  type      String // \"pdf\", \"docx\", \"pptx\", etc.\n  size      Int\n  content   Bytes? // Store file content directly\n  createdAt DateTime @default(now())\n\n  @@index([noteId])\n}\n\nmodel WorkTask {\n  id             Int       @id @default(autoincrement())\n  user           User      @relation(fields: [userId], references: [id])\n  userId         Int\n  title          String\n  context        String?\n  status         String    @default(\"todo\")\n  dueDate        DateTime?\n  source         String?\n  externalId     String?\n  followupPeople String? // JSON-encoded array of people names\n\n  @@index([userId])\n  @@index([userId, status])\n  @@index([dueDate])\n}\n\nmodel CalendarEvent {\n  id              Int      @id @default(autoincrement())\n  user            User     @relation(fields: [userId], references: [id])\n  userId          Int\n  title           String\n  description     String?\n  start           DateTime\n  end             DateTime\n  type            String\n  sourceId        String?\n  sourceExtraJson String?\n\n  @@index([userId])\n  @@index([userId, start])\n}\n\nmodel MicrosoftToken 